class Solution:
    def smallestRepunitDivByK(self, k: int) -> int:
        if k == 1:
            return 1
        if k % 2 == 0 or k % 5 == 0:
            return -1
        mod = 9 * k
        remainder = 10 % mod
        m = 1
        if remainder == 1:
            return m
        while True:
            remainder = (remainder * 10) % mod
            m += 1
            if remainder == 1:
                return m

